function:
char *mfile_name_concat(const char *dir, const char *base, char **base_in_result) {
    const char *dirbase = last_component(dir);
    size_t dirbaselen = base_len(dirbase);
    size_t dirlen = dirbase - dir + dirbaselen;
    size_t baselen = strlen(base);
    char sep = '\x00';
    if (dirbaselen) {
        if (!((dir[dirlen - 1]) == '/') && !((*base) == '/'))
            sep = '/';
    } else if (((*base) == '/')) {
        sep = '.';
    }
    char *p_concat = malloc(dirlen + (sep != '\x00') + baselen + 1);
    if (p_concat == ((void *)0))
        return ((void *)0);
    {
        char *p;
        p = mempcpy(p_concat, dir, dirlen);
        *p = sep;
        p += sep != '\x00';
        if (base_in_result)
            *base_in_result = p;
        p = mempcpy(p, base, baselen);
        *p = '\x00';
    }
